mapper.update:
update checkin c
join course co on co.id = c.course_id
set c.end_at = if(c.end_at is null or c.end_at > now(), now(), c.end_at),
    c.status = 0
where c.id = #{checkinId}
  and c.course_id = #{courseId}
  and co.teacher_id = #{teacherId}
  and co.status = 1
  and c.status = 1

mapper.select:
select count(r.id)
from checkin_record r
join checkin c on c.id = r.checkin_id
where c.course_id = #{courseId}
  and r.student_id = #{studentId}
